// Gera um item de email isolado por assistente, mantendo HTML no estilo WhatsApp
const rows = $input
  .all()
  .map(item => item.json)
  .filter(data => data && Object.keys(data).length > 0 && data.ai_assistant_id);

if (rows.length === 0) {
  return [];
}

const dataOntem = new Date();
dataOntem.setDate(dataOntem.getDate() - 1);
const dataFormatada = dataOntem.toLocaleDateString('pt-BR', {
  day: '2-digit',
  month: '2-digit',
  year: 'numeric'
});

const porAssistente = {};

function normalizarTexto(value, fallback = '') {
  if (value === null || value === undefined) return fallback;
  const texto = String(value).trim();
  return texto || fallback;
}

function normalizarEmail(value) {
  return normalizarTexto(value).toLowerCase();
}

for (const data of rows) {
  const assistenteId = data.ai_assistant_id;
  const recipient_email = normalizarEmail(data.recipient_email);

  if (!porAssistente[assistenteId]) {
    porAssistente[assistenteId] = {
      ai_assistant_id: assistenteId,
      recipient_email,
      owner_name: normalizarTexto(data.owner_name, 'Sem nome'),
      ai_assistant_name: normalizarTexto(data.ai_assistant_name, 'Assistente'),
      sessoes: {},
      total_conversas: 0,
      total_mensagens: 0,
      tiposMensagem: { text: 0, audio: 0, image: 0, outros: 0 }
    };
  } else if (!porAssistente[assistenteId].recipient_email && recipient_email) {
    porAssistente[assistenteId].recipient_email = recipient_email;
  }

  const assistente = porAssistente[assistenteId];

  if (!data.id || !data.session_id || !data.created_at) {
    continue;
  }

  assistente.total_mensagens += 1;

  if (data.message_type === 'text') assistente.tiposMensagem.text += 1;
  else if (data.message_type === 'audio') assistente.tiposMensagem.audio += 1;
  else if (data.message_type === 'image') assistente.tiposMensagem.image += 1;
  else assistente.tiposMensagem.outros += 1;

  if (!assistente.sessoes[data.session_id]) {
    assistente.sessoes[data.session_id] = {
      sender: data.sender,
      profile_name: data.profile_name || data.sender_name || data.sender,
      mensagens: []
    };
    assistente.total_conversas += 1;
  }

  assistente.sessoes[data.session_id].mensagens.push({
    timestamp: new Date(data.created_at),
    tipo: data.message_type,
    user_message: data.user_message,
    ai_response: data.ai_response
  });
}

function formatarHora(date) {
  return date.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
}

function escapeHtml(text) {
  if (text === null || text === undefined) return '';
  return String(text)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;')
    .replace(/\n/g, '<br>');
}

function formatWhatsApp(text) {
  if (!text) return '';
  let html = escapeHtml(text);
  html = html.replace(/\*(.*?)\*/g, '<b>$1</b>');
  html = html.replace(/\b_(.*?)_\b/g, '<i>$1</i>');
  html = html.replace(/~(.*?)~/g, '<s>$1</s>');
  html = html.replace(/```(.*?)```/gs, '<code style="background-color:#1a2730;padding:2px 4px;border-radius:3px;font-family:monospace;">$1</code>');
  return html;
}

function renderizarMensagens(sessao) {
  let html = '';

  sessao.mensagens.forEach(msg => {
    if (msg.user_message) {
      let tipoBadgeHtml = '';
      if (msg.tipo !== 'text') {
        let badgeBg = '#333';
        let badgeColor = '#ccc';
        if (msg.tipo === 'audio') {
          badgeBg = '#0a4d3f';
          badgeColor = '#7ed9c5';
        } else if (msg.tipo === 'image') {
          badgeBg = '#4a3c0a';
          badgeColor = '#e6d47d';
        }
        tipoBadgeHtml = `<span style="display:inline-block;font-size:10px;padding:2px 6px;border-radius:4px;margin-bottom:4px;font-weight:600;text-transform:uppercase;background-color:${badgeBg};color:${badgeColor};">${msg.tipo}</span><br>`;
      }

      html += `
        <div style="display:block;margin:4px 0;clear:both;overflow:hidden;text-align:left;">
          <div style="display:inline-block;max-width:65%;padding:8px 12px;border-radius:0 8px 8px 8px;background-color:#202c33;color:#e9edef;word-wrap:break-word;text-align:left;">
            ${tipoBadgeHtml}<div style="margin-top:4px;">${formatWhatsApp(msg.user_message)}</div>
            <div style="font-size:11px;color:#8696a0;margin-top:4px;text-align:right;">${formatarHora(msg.timestamp)}</div>
          </div>
        </div>
`;
    }

    if (msg.ai_response) {
      html += `
        <div style="display:block;margin:4px 0;clear:both;overflow:hidden;text-align:right;">
          <div style="display:inline-block;max-width:65%;padding:8px 12px;border-radius:8px 0 8px 8px;background-color:#005c4b;color:#ffffff;word-wrap:break-word;text-align:left;">
            <div style="margin-top:4px;">${formatWhatsApp(msg.ai_response)}</div>
            <div style="font-size:11px;color:#b8d4c6;margin-top:4px;text-align:right;">${formatarHora(msg.timestamp)}</div>
          </div>
        </div>
`;
    }
  });

  return html;
}

function gerarHtmlAssistente(assistente) {
  const sessoes = Object.values(assistente.sessoes)
    .map(sessao => ({
      ...sessao,
      mensagens: [...sessao.mensagens].sort((a, b) => a.timestamp - b.timestamp)
    }));

  let html = `<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Resumo diário do WhatsApp - ${escapeHtml(assistente.owner_name)} - ${dataFormatada}</title>
</head>
<body style="margin:0;padding:20px;background-color:#0b141a;color:#e9edef;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;line-height:1.5;">
  <div style="max-width:900px;margin:0 auto;background-color:#111b21;border-radius:8px;overflow:hidden;">
    <div style="background:linear-gradient(135deg,#005c4b 0%,#128c7e 100%);padding:30px;text-align:center;border-bottom:3px solid #00a884;">
      <h1 style="margin:0 0 8px 0;padding:0;font-size:28px;color:#ffffff;">&#128202; Resumo diário do WhatsApp</h1>
      <div style="font-size:18px;color:#ffffff;font-weight:600;margin-bottom:6px;">${escapeHtml(assistente.owner_name)}</div>
      <div style="font-size:16px;color:#d1f4dd;font-weight:500;margin-top:8px;">${dataFormatada}</div>
    </div>

    <div style="padding:25px;background-color:#1a2730;border-bottom:1px solid #2a3942;">
      <table width="100%" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse;">
        <tr>
          <td width="33%" style="padding:8px;" valign="top">
            <div style="background-color:#202c33;padding:15px;border-radius:8px;text-align:center;border-left:4px solid #00a884;">
              <div style="font-size:12px;color:#8696a0;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:5px;">Total de Conversas</div>
              <div style="font-size:24px;font-weight:bold;color:#00a884;">${assistente.total_conversas}</div>
            </div>
          </td>
          <td width="33%" style="padding:8px;" valign="top">
            <div style="background-color:#202c33;padding:15px;border-radius:8px;text-align:center;border-left:4px solid #00a884;">
              <div style="font-size:12px;color:#8696a0;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:5px;">Total de Mensagens</div>
              <div style="font-size:24px;font-weight:bold;color:#00a884;">${assistente.total_mensagens}</div>
            </div>
          </td>
          <td width="34%" style="padding:8px;" valign="top">
            <div style="background-color:#202c33;padding:15px;border-radius:8px;text-align:center;border-left:4px solid #00a884;">
              <div style="font-size:12px;color:#8696a0;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:5px;">Mensagens de Texto</div>
              <div style="font-size:24px;font-weight:bold;color:#00a884;">${assistente.tiposMensagem.text}</div>
            </div>
          </td>
        </tr>
        <tr>
          <td width="33%" style="padding:8px;" valign="top">
            <div style="background-color:#202c33;padding:15px;border-radius:8px;text-align:center;border-left:4px solid #00a884;">
              <div style="font-size:12px;color:#8696a0;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:5px;">Mensagens de Áudio</div>
              <div style="font-size:24px;font-weight:bold;color:#00a884;">${assistente.tiposMensagem.audio}</div>
            </div>
          </td>
          <td width="33%" style="padding:8px;" valign="top">
            <div style="background-color:#202c33;padding:15px;border-radius:8px;text-align:center;border-left:4px solid #00a884;">
              <div style="font-size:12px;color:#8696a0;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:5px;">Imagens</div>
              <div style="font-size:24px;font-weight:bold;color:#00a884;">${assistente.tiposMensagem.image}</div>
            </div>
          </td>
          <td width="34%" style="padding:8px;" valign="top">
            <div style="background-color:#202c33;padding:15px;border-radius:8px;text-align:center;border-left:4px solid #00a884;">
              <div style="font-size:12px;color:#8696a0;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:5px;">Outros Tipos</div>
              <div style="font-size:24px;font-weight:bold;color:#00a884;">${assistente.tiposMensagem.outros}</div>
            </div>
          </td>
        </tr>
      </table>
    </div>
`;

  if (sessoes.length === 0) {
    html += `
    <div style="margin:20px;background-color:#1a2730;border-radius:8px;padding:24px;border:1px solid #2a3942;text-align:center;">
      <div style="font-size:18px;font-weight:600;color:#e9edef;margin-bottom:8px;">Nenhuma conversa no período</div>
      <div style="font-size:14px;color:#8696a0;">Não houve mensagens registradas para ${escapeHtml(assistente.ai_assistant_name)} no dia ${dataFormatada}.</div>
    </div>
`;
  }

  for (const sessao of sessoes) {
    const numMensagens = sessao.mensagens.length;
    const primeiraMsg = sessao.mensagens[0];
    const ultimaMsg = sessao.mensagens[sessao.mensagens.length - 1];

    html += `
    <div style="margin:20px;background-color:#0b141a;border-radius:8px;padding:15px;border:1px solid #2a3942;">
      <table width="100%" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse;margin-bottom:15px;padding-bottom:10px;border-bottom:1px solid #2a3942;">
        <tr>
          <td style="font-size:16px;font-weight:600;color:#e9edef;">&#128172; ${escapeHtml(sessao.profile_name)} <span style="font-weight:400;font-size:13px;color:#8696a0;">${escapeHtml(sessao.sender)}</span></td>
          <td style="font-size:12px;color:#8696a0;text-align:right;">${numMensagens} mensagem(s) &bull; ${formatarHora(primeiraMsg.timestamp)} - ${formatarHora(ultimaMsg.timestamp)}</td>
        </tr>
      </table>
      <div style="display:block;">
${renderizarMensagens(sessao)}
      </div>
    </div>
`;
  }

  html += `
    <div style="text-align:center;padding:20px;color:#8696a0;font-size:12px;background-color:#1a2730;border-top:1px solid #2a3942;">
      Resumo diário gerado automaticamente para ${escapeHtml(assistente.ai_assistant_name)} em ${dataFormatada}.
    </div>
  </div>
</body>
</html>
`;

  return html;
}

return Object.values(porAssistente)
  .filter(assistente => assistente.recipient_email)
  .map(assistente => ({
    json: {
      ai_assistant_id: assistente.ai_assistant_id,
      recipient_email: assistente.recipient_email,
      ai_assistant_name: assistente.ai_assistant_name,
      owner_name: assistente.owner_name,
      data_ontem: dataFormatada,
      total_conversas: assistente.total_conversas,
      total_mensagens: assistente.total_mensagens,
      email_subject: assistente.total_mensagens > 0
        ? `📊 Resumo diário do WhatsApp — ${assistente.owner_name} — ${dataFormatada}`
        : `📭 Resumo diário do WhatsApp — ${assistente.owner_name} — ${dataFormatada}`,
      html: gerarHtmlAssistente(assistente)
    }
  }));
